ValidationRule.errorConditionFormula:
AND(
    /* 1. Prüfung auf Feldänderungen */
    OR(
        ISCHANGED(ClosingBonusInProzent__c),
        ISCHANGED(BeratungsprovisionMitPVInProzent__c),
        ISCHANGED(ProvisionsverzichtInProzent__c),
        ISCHANGED(ErfolgsabhaengigeProvision__c)
    ),
    /* 2. Ausschlusskriterien (Regel greift NICHT, wenn einer dieser Punkte wahr ist) */
    NOT(
        OR(
            $Profile.Name = "0_Controlling",
            $Profile.Name = "0_BackOffice",
            /* Admin-Ausnahme via ID */
            LEFT($User.ProfileId, 15) = "00eb0000000VEnA",
            /* Spezifische User-ID Ausnahme */
            LEFT($User.Id, 15) = "005Vi000004vBnd" 
        )
    )
)
